import{_ as i,r as d,o as t,c as r,a as e,d as h,e as c,b as o}from"./app.115d8735.js";const n={},g=c(`<h1 id="git" tabindex="-1"><a class="header-anchor" href="#git" aria-hidden="true">#</a> Git</h1><h2 id="git-init" tabindex="-1"><a class="header-anchor" href="#git-init" aria-hidden="true">#</a> git init</h2><p><code>git init</code> -- \u521D\u59CB\u5316\u4ED3\u5E93</p><h2 id="git-status" tabindex="-1"><a class="header-anchor" href="#git-status" aria-hidden="true">#</a> git status</h2><p><code>git status</code> -- \u67E5\u770B\u4ED3\u5E93\u7684\u72B6\u6001</p><h2 id="git-add-files" tabindex="-1"><a class="header-anchor" href="#git-add-files" aria-hidden="true">#</a> git add files</h2><p><code>git add files</code> -- \u5411\u6682\u5B58\u533A\u4E2D\u6DFB\u52A0\u6587\u4EF6(\u6682\u5B58\u533A\u662F\u63D0\u4EA4\u4E4B\u524D\u7684\u4E00\u4E2A\u4E34\u65F6\u533A\u57DF)</p><h2 id="git-commit" tabindex="-1"><a class="header-anchor" href="#git-commit" aria-hidden="true">#</a> git commit</h2><p><code>git commit</code> -- \u4FDD\u5B58\u4ED3\u5E93\u7684\u5386\u53F2\u8BB0\u5F55(\u5C06\u5F53\u524D\u6682\u5B58\u533A\u4E2D\u7684\u6587\u4EF6\u5B9E\u9645\u4FDD\u5B58\u5230\u4ED3\u5E93\u7684\u5386\u53F2\u8BB0\u5F55\u4E2D)</p><ul><li><code>-m &#39;message&#39;</code>: -m \u540E\u7684\u53C2\u6570\u79F0\u4F5C\u63D0\u4EA4\u4FE1\u606F\uFF0C\u662F\u5BF9\u8FD9\u4E2A\u63D0\u4EA4\u7684\u6982\u8FF0\u3002</li></ul><p><strong>\u5982\u679C\u8BB0\u8FF0\u5F97\u66F4\u52A0\u8BE6\u7EC6</strong>\uFF0C\u8BF7\u4E0D\u8981\u6DFB\u52A0 <code>-m</code>\uFF0C \u76F4\u63A5<code>git commit</code> \u547D\u4EE4\uFF0C\u6267\u884C\u540E\u7F16\u8F91\u5668\u5C31\u4F1A\u542F\u52A8</p><ul><li>\u7B2C\u4E00\u884C\uFF1A\u7528\u4E00\u884C\u6587\u5B57\u7B80\u8FF0\u63D0\u4EA4\u7684\u66F4\u6539\u5185\u5BB9\u3002</li><li>\u7B2C\u4E8C\u884C\uFF1A\u7A7A\u884C</li><li>\u7B2C\u4E09\u884C\u4EE5\u540E\uFF1A\u8BB0\u8FF0\u66F4\u6539\u7684\u539F\u56E0\u548C\u8BE6\u7EC6\u5185\u5BB9\u3002</li></ul><p><strong>\u4E2D\u6B62\u63D0\u4EA4</strong>\uFF1A</p><ul><li>\u5982\u679C\u5728\u7F16\u8F91\u5668\u6253\u5F00\u540E\u5148\u4E2D\u6B62\u63D0\u4EA4\uFF0C\u8BF7\u5C06\u63D0\u4EA4\u4FE1\u606F\u7559\u7A7A\u76F4\u63A5\u5173\u95ED\u7F16\u8F91\u5668\uFF0C\u968F\u540E\u63D0\u4EA4\u5C31\u4F1A\u88AB\u4E2D\u6B62\u3002</li></ul><h3 id="git-commit-amend" tabindex="-1"><a class="header-anchor" href="#git-commit-amend" aria-hidden="true">#</a> git commit --amend</h3><p><code>git commit --amend</code> -- \u91CD\u65B0\u4FEE\u6539\u63D0\u4EA4\u4FE1\u606F\uFF0C\u4E14\u7B2C\u4E8C\u4E2A\u63D0\u4EA4\u4F1A\u4EE3\u66FF\u7B2C\u4E00\u4E2A\u63D0\u4EA4\uFF0C\u5982\u679C\u6B64\u65F6\u6682\u5B58\u533A\u6709\u6587\u4EF6\uFF0C\u5219\u4F1A\u88AB\u63D0\u4EA4\u3002</p><h3 id="git-commit-a-m" tabindex="-1"><a class="header-anchor" href="#git-commit-a-m" aria-hidden="true">#</a> git commit -a -m</h3><p><code>git commit -a -m &#39;xxx&#39;</code> -- \u81EA\u52A8\u628A\u6240\u6709\u5DF2\u7ECF\u8DDF\u8E2A\u8FC7\u7684\u6587\u4EF6\u6682\u5B58\u8D77\u6765<strong>\u4E00\u5E76\u63D0\u4EA4</strong>\uFF0C\u4ECE\u800C\u8DF3\u8FC7<code>git add</code> \u6B65\u9AA4</p><h2 id="git-blame" tabindex="-1"><a class="header-anchor" href="#git-blame" aria-hidden="true">#</a> git blame</h2><p><code>git blame &lt;file&gt;</code> -- \u67E5\u770B\u8C01\u6539\u53D8\u4E86\u6587\u4EF6</p><h2 id="git-checkout" tabindex="-1"><a class="header-anchor" href="#git-checkout" aria-hidden="true">#</a> git checkout</h2><h3 id="git-checkout-files" tabindex="-1"><a class="header-anchor" href="#git-checkout-files" aria-hidden="true">#</a> git checkout -- files</h3><p><code>git checkout -- files</code> \u628A\u6587\u4EF6\u4ECE\u6682\u5B58\u533A\u590D\u5236\u5230\u5DE5\u4F5C\u76EE\u5F55\uFF0C\u7528\u6765\u4E22\u5F03\u672C\u5730\u4FEE\u6539\u3002</p><h3 id="git-checkout-b-xxx" tabindex="-1"><a class="header-anchor" href="#git-checkout-b-xxx" aria-hidden="true">#</a> git checkout -b xxx</h3><p><code>git checkout -b xxx</code> -- \u521B\u5EFA\u5E76\u5207\u6362\u5230 xxx \u5206\u652F</p><p>\u7B49\u540C\u4E8E\uFF1A<code>git branch feature-A &amp;&amp; git checkout feature-A</code></p><p>\u4E0D\u65AD\u5BF9\u4E00\u4E2A\u5206\u652F\u8FDB\u884C\u63D0\u4EA4\uFF0C\u6211\u4EEC\u8FDB\u884C\u8FD9\u6837\u7684\u64CD\u4F5C\uFF0C\u6211\u4EEC\u79F0\u4E3A<strong>\u57F9\u80B2\u5206\u652F</strong>\u3002</p><h3 id="git-checkout-1" tabindex="-1"><a class="header-anchor" href="#git-checkout-1" aria-hidden="true">#</a> git checkout -</h3><p><code>git checkout -</code> -- \u5207\u6362\u56DE\u4E0A\u4E00\u4E2A\u5206\u652F</p><h3 id="git-checkout-\u2014-file" tabindex="-1"><a class="header-anchor" href="#git-checkout-\u2014-file" aria-hidden="true">#</a> git checkout\u2009\u2014\u2009file</h3><p><code>git checkout \u2014 [file]</code> -- \u5BF9\u6587\u4EF6\u505A\u7684\u4EFB\u4F55\u90FD\u4F1A\u6D88\u5931\uFF0C\u8FD8\u539F\u6210\u4E0A\u4E00\u6B21\u63D0\u4EA4\u7684\u6837\u5B50\uFF0C\u662F\u4E00\u4E2A\u5371\u9669\u7684\u547D\u4EE4</p><h3 id="git-checkout-xxx" tabindex="-1"><a class="header-anchor" href="#git-checkout-xxx" aria-hidden="true">#</a> git checkout xxx</h3><p><code>git checkout xxx</code> -- \u5207\u6362\u5230 xxx \u5206\u652F</p><h2 id="git-log" tabindex="-1"><a class="header-anchor" href="#git-log" aria-hidden="true">#</a> git log</h2><h3 id="git-log-1" tabindex="-1"><a class="header-anchor" href="#git-log-1" aria-hidden="true">#</a> git log</h3><p><code>git log</code> -- \u67E5\u770B\u63D0\u4EA4\u65E5\u5FD7(\u67E5\u770B\u4EE5\u5F80\u4ED3\u5E93\u4E2D\u63D0\u4EA4\u7684\u65E5\u5FD7\uFF0C\u5305\u62EC\u53EF\u4EE5\u770B\u4EC0\u4E48\u4EBA\u5728\u4EC0\u4E48\u65F6\u5019\u8FDB\u884C\u4E86\u63D0\u4EA4\u6216\u5408\u5E76\uFF0C\u4EE5\u53CA\u64CD\u4F5C\u524D\u540E\u7684\u5DEE\u522B)\u3001\u53EA\u80FD\u67E5\u770B\u4EE5\u5F53\u524D\u72B6\u6001\u4E3A\u7EC8\u70B9\u7684\u5386\u53F2\u65E5\u5FD7\u3002</p><h3 id="git-log-xxx" tabindex="-1"><a class="header-anchor" href="#git-log-xxx" aria-hidden="true">#</a> git log xxx</h3><p><strong>\u53EA\u663E\u793A\u6307\u5B9A\u76EE\u5F55\u3001\u6587\u4EF6\u7684\u65E5\u5FD7</strong>\uFF1A</p><ul><li>\u53EA\u9700\u8981\u5728<code>git log</code> \u547D\u4EE4\u540E\u52A0\u4E0A\u76EE\u5F55\u540D\uFF0C\u4FBF\u4F1A\u53EA\u663E\u793A\u6539\u76EE\u5F55\u4E0B\u7684\u65E5\u5FD7\u3002</li><li>\u5982\u679C\u52A0\u7684\u662F\u6587\u4EF6\u540D\uFF0C\u5C31\u4F1A\u53EA\u663E\u793A\u8BE5\u6587\u4EF6\u76F8\u5173\u7684\u65E5\u5FD7 <code>git log README.md</code></li></ul><h3 id="git-log-pretty" tabindex="-1"><a class="header-anchor" href="#git-log-pretty" aria-hidden="true">#</a> git log --pretty</h3><p><strong>\u53EA\u663E\u793A\u63D0\u4EA4\u4FE1\u606F\u7684\u7B2C\u4E00\u884C</strong>\uFF0C\u53EF\u4EE5\u4F7F\u7528<code>git log --pretty=short</code>\uFF0C\u8FD9\u6837\u5F00\u53D1\u4EBA\u5458\u5C31\u53EF\u4EE5\u8F7B\u677E\u628A\u63E1\u591A\u4E2A\u63D0\u4EA4\u3002</p><h3 id="git-log-p-xxx" tabindex="-1"><a class="header-anchor" href="#git-log-p-xxx" aria-hidden="true">#</a> git log -p xxx</h3><p><strong>\u663E\u793A\u6587\u4EF6\u6BCF\u6B21\u63D0\u4EA4\u7684\u5185\u5BB9\u5DEE\u5F02</strong>\uFF1A</p><ul><li>\u5982\u679C\u60F3\u67E5\u770B\u63D0\u4EA4\u6240\u5E26\u6765\u7684\u7684\u6539\u52A8\uFF0C\u53EF\u4EE5\u52A0\u4E0A<code>-p</code> \u53C2\u6570\uFF0C\u6587\u4EF6\u7684\u524D\u540E\u5DEE\u522B\u5C31\u4F1A\u663E\u793A\u5728\u63D0\u4EA4\u4FE1\u606F\u4E4B\u540E</li></ul><p><code>git log -p README.md</code> <strong>\u53EA\u67E5\u770B<code>README.md</code> \u6587\u4EF6\u7684\u63D0\u4EA4\u65E5\u5FD7\u4EE5\u53CA\u63D0\u4EA4\u524D\u540E\u7684\u5DEE\u522B</strong></p><h3 id="git-log-stat" tabindex="-1"><a class="header-anchor" href="#git-log-stat" aria-hidden="true">#</a> git log --stat</h3><p>\u770B<strong>\u6BCF\u6B21\u63D0\u4EA4\u7684\u7B80\u7565\u7684\u7EDF\u8BA1\u4FE1\u606F</strong>\uFF0C\u4F60\u53EF\u4EE5\u4F7F\u7528 <code>--stat</code> \u9009\u9879\uFF1A\u5728\u6BCF\u6B21\u63D0\u4EA4\u7684\u4E0B\u9762\u5217\u51FA\u989D\u6240\u6709\u88AB\u4FEE\u6539\u8FC7\u7684\u6587\u4EF6\u3001\u6709\u591A\u5C11\u6587\u4EF6\u88AB\u4FEE\u6539\u4E86\u4EE5\u53CA\u88AB\u4FEE\u6539\u8FC7\u7684\u6587\u4EF6\u7684\u54EA\u4E9B\u884C\u88AB\u79FB\u9664\u6216\u662F\u6DFB\u52A0\u4E86\u3002 \u5728\u6BCF\u6B21\u63D0\u4EA4\u7684\u6700\u540E\u8FD8\u6709\u4E00\u4E2A\u603B\u7ED3\u3002</p><h3 id="git-log-graph" tabindex="-1"><a class="header-anchor" href="#git-log-graph" aria-hidden="true">#</a> git log --graph</h3><p><code>git log --graph</code> -- \u4EE5\u56FE\u6807\u7684\u5F62\u5F0F\u67E5\u770B\u5206\u652F</p><h2 id="git-diff" tabindex="-1"><a class="header-anchor" href="#git-diff" aria-hidden="true">#</a> git diff</h2><h3 id="git-diff-1" tabindex="-1"><a class="header-anchor" href="#git-diff-1" aria-hidden="true">#</a> git diff</h3><p><code>git diff</code> -- \u67E5\u770B\u5C1A\u672A\u6682\u5B58\u7684\u6539\u52A8</p><h3 id="git-diff-head" tabindex="-1"><a class="header-anchor" href="#git-diff-head" aria-hidden="true">#</a> git diff HEAD</h3><p><code>git diff HEAD</code> -- \u67E5\u770B\u5DE5\u4F5C\u6811\u4E0E\u6700\u65B0\u63D0\u4EA4\u7684\u533A\u522B</p><h3 id="git-diff-cached" tabindex="-1"><a class="header-anchor" href="#git-diff-cached" aria-hidden="true">#</a> git diff --cached</h3><p><code>git diff --cached(staged)</code> -- \u67E5\u770B\u5DF2\u7ECF\u6682\u5B58\u8D77\u6765\u7684\u6539\u52A8</p><h3 id="git-diff-hash1-hash2" tabindex="-1"><a class="header-anchor" href="#git-diff-hash1-hash2" aria-hidden="true">#</a> git diff hash1 hash2</h3><p><code>git diff hash1 hash2</code> -- \u67E5\u770B\u4E24\u4E2A\u6587\u4EF6\u4E4B\u95F4\u7684\u533A\u522B</p><h2 id="git-rm" tabindex="-1"><a class="header-anchor" href="#git-rm" aria-hidden="true">#</a> git rm</h2><p>\u8981\u4ECE Git \u4E2D\u79FB\u9664\u67D0\u4E2A\u6587\u4EF6\uFF0C\u5C31\u5FC5\u987B\u8981\u4ECE\u5DF2\u8DDF\u8E2A\u6587\u4EF6\u6E05\u5355\u4E2D\u79FB\u9664\uFF08\u786E\u5207\u5730\u8BF4\uFF0C\u662F\u4ECE\u6682\u5B58\u533A\u57DF\u79FB\u9664\uFF09\uFF0C\u7136\u540E\u63D0\u4EA4\u3002</p><p><code>git rm</code> -- \u8FDE\u5E26\u4ECE\u5DE5\u4F5C\u76EE\u5F55\u4E2D\u5220\u9664\u6307\u5B9A\u7684\u6587\u4EF6\uFF0C\u8FD9\u6837\u4EE5\u540E\u5C31\u4E0D\u4F1A\u51FA\u73B0\u5728\u672A\u8DDF\u8E2A\u6587\u4EF6\u6E05\u5355\u4E2D\u4E86\u3002</p><h3 id="git-rm-f" tabindex="-1"><a class="header-anchor" href="#git-rm-f" aria-hidden="true">#</a> git rm -f</h3><p><code>git rm -f</code> -- \u5982\u679C\u5220\u9664\u4E4B\u524D\u4FEE\u6539\u8FC7\u5E76\u4E14\u5DF2\u7ECF\u653E\u5230\u6682\u5B58\u533A\u57DF\u7684\u8BDD\uFF0C\u5219\u5FC5\u987B\u8981\u7528\u5F3A\u5236\u5220\u9664\u9009\u9879<code>-f</code></p><h3 id="git-rm-cached-readme" tabindex="-1"><a class="header-anchor" href="#git-rm-cached-readme" aria-hidden="true">#</a> git rm --cached README</h3><p><code>git rm --cached README</code> -- \u4ECE Git \u4ED3\u5E93\uFF08\u6682\u5B58\u533A\u57DF\uFF09\u5220\u9664\uFF0C\u4F46\u662F\u4ECD\u4FDD\u7559\u5728\u672C\u5730\u5DE5\u4F5C\u76EE\u5F55</p><h2 id="git-mv" tabindex="-1"><a class="header-anchor" href="#git-mv" aria-hidden="true">#</a> git mv</h2><p><code>git mv file_from file_to</code> -- \u5728 Git \u4E2D\u5BF9\u6587\u4EF6\u6539\u540D\uFF0C\u76F8\u5F53\u4E8E\u8FD0\u884C\u4E86\u4E0B\u9762\u4E09\u6BB5\u547D\u4EE4</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>$ <span class="token function">mv</span> README.md README
$ <span class="token function">git</span> <span class="token function">rm</span> README.md
$ <span class="token function">git</span> <span class="token function">add</span> README
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="git-branch" tabindex="-1"><a class="header-anchor" href="#git-branch" aria-hidden="true">#</a> git branch</h2><h3 id="git-branch-1" tabindex="-1"><a class="header-anchor" href="#git-branch-1" aria-hidden="true">#</a> git branch</h3><p><code>git branch</code> -- \u663E\u793A\u672C\u5730\u6240\u6709\u5206\u652F</p><h3 id="git-branch-av" tabindex="-1"><a class="header-anchor" href="#git-branch-av" aria-hidden="true">#</a> git branch -av</h3><p><code>git branch -av</code> -- \u663E\u793A\u6240\u6709\u5206\u652F\uFF0C\u5305\u62EC\u8FDC\u7A0B\u5206\u652F</p><h3 id="git-branch-xxx" tabindex="-1"><a class="header-anchor" href="#git-branch-xxx" aria-hidden="true">#</a> git branch xxx</h3><p><code>git branch xxx</code> -- \u65B0\u5EFA xxx \u5206\u652F</p><h3 id="git-branch-a" tabindex="-1"><a class="header-anchor" href="#git-branch-a" aria-hidden="true">#</a> git branch -a</h3><p><code>git branch -a</code> -- \u67E5\u770B\u5F53\u524D\u5206\u652F\u7684\u76F8\u5173\u4FE1\u606F\uFF0C\u6DFB\u52A0 <code>-a</code> \u53EF\u4EE5\u540C\u65F6\u663E\u793A\u672C\u5730\u4ED3\u5E93\u548C\u8FDC\u7A0B\u4ED3\u5E93\u7684\u5206\u652F\u4FE1\u606F</p><h3 id="git-branch-d-xxx" tabindex="-1"><a class="header-anchor" href="#git-branch-d-xxx" aria-hidden="true">#</a> git branch -d xxx</h3><p><code>git branch -d xxx</code> -- \u5220\u9664<strong>\u672C\u5730</strong><code>xxx</code> \u5206\u652F\uFF0C\u6CE8\u610F\uFF0C\u5220\u9664\u5206\u652F\u524D\uFF0C\u9700\u8981\u5207\u6362\u5230\u5176\u4ED6\u5206\u652F</p><h3 id="git-push-origin-delete-xxx" tabindex="-1"><a class="header-anchor" href="#git-push-origin-delete-xxx" aria-hidden="true">#</a> git push origin --delete xxx</h3><p><code>git push origin --delete xxx</code> -- \u5220\u9664<strong>\u8FDC\u7A0B</strong><code>xxx</code> \u5206\u652F\uFF0C\u6CE8\u610F\uFF0C\u5220\u9664\u5206\u652F\u524D\uFF0C\u9700\u8981\u5207\u6362\u5230\u5176\u4ED6\u5206\u652F</p><h2 id="git-merge" tabindex="-1"><a class="header-anchor" href="#git-merge" aria-hidden="true">#</a> git merge</h2><h3 id="git-merge-1" tabindex="-1"><a class="header-anchor" href="#git-merge-1" aria-hidden="true">#</a> git merge</h3><p><code>git merge</code> -- \u5408\u5E76\u5206\u652F</p><h3 id="git-merge-no-ff-xxx" tabindex="-1"><a class="header-anchor" href="#git-merge-no-ff-xxx" aria-hidden="true">#</a> git merge --no-ff xxx</h3><p><code>git merge --no-ff xxx</code> \u5408\u5E76 xxx \u5206\u652F\uFF0C\u4E3A\u4E86\u5728\u5386\u53F2\u8BB0\u5F55\u4E2D\u660E\u786E\u8BB0\u5F55\u4E0B\u672C\u6B21\u5206\u652F\u5408\u5E76\uFF0C\u6211\u4EEC\u9700\u8981\u521B\u5EFA\u5408\u5E76\u63D0\u4EA4\u3002\u56E0\u6B64\uFF0C\u5728\u5408\u5E76\u65F6\u52A0\u4E0A <code>--no-ff</code> \u53C2\u6570\u3002\u968F\u540E\u4FDD\u5B58\u5408\u5E76\u4FE1\u606F\u3002</p><blockquote><p>\u6CE8\u610F \u{1F4E2}\uFF1A\u5408\u5E76\u5206\u652F\u9700\u8981\u5148\u5207\u6362\u5230\u4E3B\u5206\u652F(main)\u3001\u8FD9\u6837 xxx \u5206\u652F\u7684\u5185\u5BB9\u5C31\u5408\u5E76\u5230\u4E86 main \u5206\u652F\u4E0A</p></blockquote><h2 id="git-reset" tabindex="-1"><a class="header-anchor" href="#git-reset" aria-hidden="true">#</a> git reset</h2><h3 id="git-reset-head-files" tabindex="-1"><a class="header-anchor" href="#git-reset-head-files" aria-hidden="true">#</a> git reset HEAD files</h3><p><code>git reset HEAD files</code> \u7528\u6765\u64A4\u9500 files \u6587\u4EF6\u7684\u6682\u5B58\uFF0C\u4E5F\u53EF\u4EE5\u4F7F\u7528<code>git reset</code> \u64A4\u9500\u6240\u6709\u6682\u5B58\u533A\u57DF\u7684\u6587\u4EF6\u3002</p><h3 id="git-reset-hard-xxxx-\u54C8\u5E0C\u503C" tabindex="-1"><a class="header-anchor" href="#git-reset-hard-xxxx-\u54C8\u5E0C\u503C" aria-hidden="true">#</a> git reset --hard xxxx(\u54C8\u5E0C\u503C)</h3><p><code>git reset --hard xxxx(\u54C8\u5E0C\u503C)</code> -- \u56DE\u6EAF\u5230\u7279\u6027\u5206\u652F xxx</p><h3 id="git-reset-hard-head" tabindex="-1"><a class="header-anchor" href="#git-reset-hard-head" aria-hidden="true">#</a> git reset --hard HEAD</h3><p><code>git reset --hard HEAD</code> -- \u56DE\u9000\u6240\u6709\u6539\u52A8\u5230\u5F53\u524D\u7248\u672C</p><h2 id="git-reflog" tabindex="-1"><a class="header-anchor" href="#git-reflog" aria-hidden="true">#</a> git reflog</h2><p><code>git reflog</code> -- <strong>\u67E5\u770B\u5F53\u524D\u4ED3\u5E93\u7684\u64CD\u4F5C\u65E5\u5FD7</strong></p><blockquote><p><code>git log</code> \u53EA\u80FD\u67E5\u770B\u4EE5\u5F53\u524D\u72B6\u6001\u4E3A\u7EC8\u70B9\u7684\u5386\u53F2\u65E5\u5FD7</p></blockquote><h2 id="git-rebase" tabindex="-1"><a class="header-anchor" href="#git-rebase" aria-hidden="true">#</a> git rebase</h2><h3 id="git-rebase-branch" tabindex="-1"><a class="header-anchor" href="#git-rebase-branch" aria-hidden="true">#</a> git rebase branch</h3><p><code>git rebase branch</code> <code>Rebase</code>\u5F53\u524D\u7684<code>HEAD</code> \u5230<code>branch</code> \u540E\u9762</p><h3 id="git-rebase-i-head-2" tabindex="-1"><a class="header-anchor" href="#git-rebase-i-head-2" aria-hidden="true">#</a> git rebase -i HEAD~2</h3><p><code>git rebase -i HEAD~2</code> \u5408\u5E76\u6700\u8FD1\u4E24\u6B21\u7684<code>commit</code> \u4E3A\u4E00\u6B21<code>commit</code></p><p>\u6267\u884C\u5B8C\u540E\uFF0C\u5C06<code>pick</code> \u540E\u7684\u63D0\u4EA4\u4FE1\u606F\u4FDD\u5B58\u4E3A<code>commit</code>\uFF0C\u9700\u8981\u5220\u9664\u7684<code>commit</code> \u4FE1\u606F\u524D\u4FEE\u6539\u4E3A<code>fixup</code></p><h2 id="git-remote-add" tabindex="-1"><a class="header-anchor" href="#git-remote-add" aria-hidden="true">#</a> git remote add</h2><p><code>git remote add</code> -- \u5C06\u94FE\u63A5\u5730\u5740\u8BBE\u7F6E\u4E3A\u672C\u5730\u4ED3\u5E93\u7684\u8FDC\u7A0B\u4ED3\u5E93</p><p>\u5728\u672C\u5730\u4E0A\u521B\u5EFA\u7684\u4ED3\u5E93\u7684\u8DEF\u5F84\u4E3A<code>git@github.com: \u7528\u6237\u540D/git-tutorial.git</code></p><p><code>git remote add origin git@github.com: \u7528\u6237\u540D/git-tutorial.git</code> Git \u4F1A\u81EA\u52A8\u5C06\u8FDC\u7A0B\u4ED3\u5E93\u540D\u79F0\u8BBE\u7F6E \u4E3A origin</p><h2 id="git-push" tabindex="-1"><a class="header-anchor" href="#git-push" aria-hidden="true">#</a> git push</h2><p>\u63A8\u9001\u81F3 master \u5206\u652F <code>git push -u origin master</code></p><p><code>-u</code> \u53C2\u6570\u53EF\u4EE5\u5728\u63A8\u9001\u7684\u540C\u65F6\uFF0C\u5C06 origin \u4ED3\u5E93\u7684 master \u5206\u652F\u8BBE\u7F6E\u4E3A\u672C\u5730\u4ED3\u5E93\u5F53\u524D\u5206\u652F\u7684\u4E0A\u6E38\u3002</p><h2 id="\u53C2\u8003\u6587\u732E" tabindex="-1"><a class="header-anchor" href="#\u53C2\u8003\u6587\u732E" aria-hidden="true">#</a> \u53C2\u8003\u6587\u732E</h2>`,111),s={href:"https://zhuanlan.zhihu.com/p/340043244",target:"_blank",rel:"noopener noreferrer"},x=o("merge \u548C rebase \u7684\u7406\u89E3");function l(p,f){const a=d("ExternalLinkIcon");return t(),r("div",null,[g,e("ul",null,[e("li",null,[e("a",s,[x,h(a)])])])])}var m=i(n,[["render",l],["__file","index.html.vue"]]);export{m as default};
